import { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FiUpload, FiCpu, FiShield, FiClock, FiActivity } from 'react-icons/fi';

const Hero = () => {
  const [isDragging, setIsDragging] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const fileInputRef = useRef(null);

  const handleFileUpload = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsAnalyzing(true);
      setTimeout(() => {
        setIsAnalyzing(false);
        alert(`Analysis complete!\nFile: ${file.name}\nResult: ${Math.random() > 0.5 ? 'REAL' : 'AI-GENERATED'}`);
      }, 2000);
    }
  };

  // Inline SVG for the grid background
  const GridPattern = () => (
    <svg className="absolute inset-0 w-full h-full opacity-10 [mask-image:radial-gradient(ellipse_at_center,black,transparent_70%)]" 
         preserveAspectRatio="none">
      <pattern id="grid" width="60" height="60" patternUnits="userSpaceOnUse">
        <path d="M0 0h60v1H0zM0 20h60v1H0zM0 40h60v1H0zM0 60h60v1H0zM0 0v60h1V0zM20 0v60h1V0zM40 0v60h1V0zM60 0v60h1V0z" 
              fill="rgba(255,255,255,0.1)" />
      </pattern>
      <rect width="100%" height="100%" fill="url(#grid)" />
    </svg>
  );

  return (
    <section className="relative min-h-screen flex items-center justify-center bg-gradient-to-br from-gray-900 via-purple-900 to-violet-800 overflow-hidden isolate">
      {/* Grid background (now inline) */}
      <GridPattern />

      {/* Floating AI nodes */}
      <div className="absolute top-1/4 left-1/4 w-3 h-3 rounded-full bg-cyan-400 shadow-[0_0_20px_5px_rgba(34,211,238,0.5)] animate-float" />
      <div className="absolute top-1/3 right-1/5 w-4 h-4 rounded-full bg-purple-500 shadow-[0_0_20px_5px_rgba(168,85,247,0.5)] animate-float delay-1000" />

      {/* Main container */}
      <motion.div 
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
        className="relative z-10 w-full max-w-5xl px-6 mx-auto"
      >
        {/* Headline */}
        <div className="text-center mb-12">
          <motion.h1 
            className="text-5xl sm:text-6xl md:text-7xl font-bold mb-6 leading-tight"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.2 }}
          >
            <span className="text-white">Detect </span>
            <span className="text-transparent bg-clip-text bg-[conic-gradient(at_top_right,_var(--tw-gradient-stops))] from-amber-200 via-violet-600 to-sky-900 animate-gradient-shift">
              Deepfakes
            </span>
          </motion.h1>
          
          <motion.p 
            className="text-xl text-gray-300 max-w-2xl mx-auto"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4 }}
          >
            Advanced neural networks analyze images for AI manipulation with 96.3% accuracy
          </motion.p>
        </div>

        {/* Interactive upload card */}
        <motion.div
          className={`relative bg-gray-900/50 backdrop-blur-lg rounded-2xl p-0.5 overflow-hidden transition-all duration-300 ${
            isDragging ? 'bg-gradient-to-r from-cyan-400 to-purple-500' : 'bg-gray-900/50'
          }`}
          whileHover={{ y: -5 }}
        >
          <div 
            className={`h-64 rounded-[15px] flex flex-col items-center justify-center transition-all duration-300 ${
              isDragging ? 'bg-gray-900/80' : 'bg-gray-900/60'
            }`}
            onClick={() => fileInputRef.current.click()}
            onDragOver={(e) => {
              e.preventDefault();
              setIsDragging(true);
            }}
            onDragLeave={() => setIsDragging(false)}
            onDrop={(e) => {
              e.preventDefault();
              setIsDragging(false);
              handleFileUpload({ target: { files: e.dataTransfer.files } });
            }}
          >
            <AnimatePresence>
              {isAnalyzing ? (
                <motion.div
                  key="analyzing"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="flex flex-col items-center"
                >
                  <div className="relative w-16 h-16 mb-4">
                    <div className="absolute inset-0 rounded-full bg-cyan-400/20 animate-ping" />
                    <FiActivity className="absolute inset-0 m-auto text-3xl text-cyan-400 animate-pulse" />
                  </div>
                  <p className="text-cyan-400 font-medium">Analyzing image...</p>
                </motion.div>
              ) : (
                <motion.div
                  key="upload"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  exit={{ opacity: 0 }}
                  className="flex flex-col items-center p-6 text-center"
                >
                  <div className="p-4 mb-4 rounded-full bg-gradient-to-br from-cyan-400/10 to-purple-500/10 border border-gray-700/50">
                    <FiUpload className="text-3xl text-cyan-400" />
                  </div>
                  <h3 className="text-xl font-semibold text-white mb-2">
                    {isDragging ? 'Drop to analyze' : 'Upload image'}
                  </h3>
                  <p className="text-gray-400 mb-4">
                    Drag & drop or click to browse files
                  </p>
                  <span className="text-xs text-gray-500">
                    Supports JPG, PNG, WEBP (Max 10MB)
                  </span>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
          <input
            type="file"
            ref={fileInputRef}
            onChange={handleFileUpload}
            accept="image/*"
            className="hidden"
          />
        </motion.div>

        {/* Tech badges */}
        <motion.div 
          className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-12"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.6 }}
        >
          {[
            { icon: <FiCpu />, label: 'ResNet-152', value: 'Model' },
            { icon: <FiShield />, label: '96.3%', value: 'Accuracy' },
            { icon: <FiClock />, label: '1.8s', value: 'Avg. Speed' },
            { icon: <FiActivity />, label: 'ENS', value: 'Technology' },
          ].map((item, i) => (
            <div 
              key={i}
              className="bg-gray-900/40 backdrop-blur-sm rounded-xl p-4 border border-gray-800 hover:border-cyan-400/30 transition-colors"
            >
              <div className="text-cyan-400 mb-2 text-2xl">{item.icon}</div>
              <div className="text-2xl font-bold text-white mb-1">{item.label}</div>
              <div className="text-sm text-gray-400">{item.value}</div>
            </div>
          ))}
        </motion.div>
      </motion.div>
    </section>
  );
};

export default Hero;
